# The default GLSL TOP shader in its Text DAT looks like:
default_shader = '''
out vec4 fragColor;

void main()
{
    vec4 color = texture(sTD2DInputs[0], vUV.st);
    fragColor = TDOutputSwizzle(color);
}
'''

# Set the shader code on the Text DAT
shader = '''
out vec4 fragColor;
uniform float uTime;

void main()
{
    // Center UV coordinates
    vec2 uv = vUV.st - 0.5;

    // Distance from center
    float dist = length(uv);

    // Animated concentric rings
    float rings = sin(dist * 30.0 - uTime * 2.0);
    rings = smoothstep(0.0, 0.1, rings);

    // Color based on angle
    float angle = atan(uv.y, uv.x);
    vec3 col = vec3(
        0.5 + 0.5 * sin(angle + uTime),
        0.5 + 0.5 * sin(angle + uTime + 2.094),
        0.5 + 0.5 * sin(angle + uTime + 4.189)
    );

    fragColor = TDOutputSwizzle(vec4(col * rings, 1.0));
}
'''
op('/project1/glsl1_shader').text = shader
